(async () => {
  try {
    // Get current tab
    const currentTabs = await chrome.tabs.query({ active: true, currentWindow: true });
    const currentId = currentTabs[0].id;

    // Get all tabs
    const allTabs = await chrome.tabs.query({});
    const otherTabs = allTabs.filter(t => t.id !== currentId);

    if (otherTabs.length === 0) {
      return { success: true, message: 'No other tabs to close.', closedCount: 0 };
    }

    // Close all other tabs
    await chrome.tabs.remove(otherTabs.map(t => t.id));

    return { 
      success: true, 
      message: `Closed ${otherTabs.length} tab(s).`, 
      closedCount: otherTabs.length,
      closedUrls: otherTabs.map(t => ({ title: t.title, url: t.url }))
    };
  } catch (e) {
    return { success: false, error: e.message };
  }
})();
